SELECT

FROM repair_applications r
JOIN users s ON r.student_id = s.id
LEFT JOIN student_profiles sp ON s.id = sp.user_id
LEFT JOIN users a ON r.auditor_id = a.id
WHERE r.student_id = #{studentId}

    AND r.status = #{status}

ORDER BY r.created_at DESC, r.id DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(*)
FROM repair_applications
WHERE student_id = #{studentId}

    AND status = #{status}

SELECT
FROM repair_applications r JOIN users s ON r.student_id = s.id LEFT JOIN student_profiles sp ON s.id = sp.user_id LEFT JOIN users a ON r.auditor_id = a.id WHERE 1 = 1
AND r.status = #{status}
AND s.real_name LIKE CONCAT('%', #{studentName}, '%')
AND r.dorm_building = #{dormBuilding}
ORDER BY r.created_at DESC, r.id DESC LIMIT #{offset}, #{pageSize}

SELECT COUNT(*) FROM repair_applications r JOIN users s ON r.student_id = s.id WHERE 1 = 1
AND r.status = #{status}
AND s.real_name LIKE CONCAT('%', #{studentName}, '%')
AND r.dorm_building = #{dormBuilding}

mapper.update:
UPDATE repair_applications
SET status = 'CANCELED'
WHERE id = #{id}
  AND student_id = #{studentId}
  AND status = 'PENDING'

UPDATE repair_applications
SET status = #{status}
WHERE id = #{id}

UPDATE repair_applications
SET status = 'COMPLETED'
WHERE id = #{id}
  AND student_id = #{studentId}
  AND status IN ('APPROVED', 'REPAIRING')
